import React from "react"
import { Button } from "react-md";
import { Helmet } from "react-helmet";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";

import LayoutMain from "../layout"
import ContentCard from "../components/ContentCard"

import config from "../app-config";

export default class SocialPage extends React.Component {

  getSocialAccounts(){
    const socAcctList = [];
    config.socialLinks.forEach(link => {
      socAcctList.push({
        service: link.service,
        name: link.name,
        url: link.url,
        desc: link.description,
        icon: <Button
          floating
          svg
          style={{backgroundColor: link.iconColor ? link.iconColor : 'black' }}
          href={link.url}>
        <FontAwesomeIcon 
            color='white'
            transform='grow-24 right-5 down-4'
            icon={link.iconClassName}
            />
        </Button>

      })
    });

    return socAcctList;
  }

  render() {
    const socialAccounts = this.getSocialAccounts();
    return (
      <div>
        <Helmet>
          <title>Social Media | Amperture Engineering</title>
        </Helmet>
        <LayoutMain>
          <div className='md-grid'>
              {socialAccounts.map(acct => (
                <ContentCard
                  titleText={acct.service}
                  subtitleText={acct.name}
                  avatar={acct.icon}
                >
                  <p>{acct.desc}</p>
                </ContentCard>
              ))}
          </div>
        </LayoutMain>
      </div>
    )
  }
}
